import{_ as s,o as r,c as a,a7 as p}from"./chunks/framework.BgApuQ2e.js";const n="/images/sports-fans-sports-fans/critical-fan.png",o="/images/sports-fans-sports-fans/Jersey.png",e="/images/sports-fans-sports-fans/Face-1.png",g="/images/sports-fans-sports-fans/Face-2.png",i="/images/sports-fans-sports-fans/Face-3.png",l="/images/sports-fans-sports-fans/riot1.png",f="/images/sports-fans-sports-fans/golf.png",c="/images/sports-fans-sports-fans/brady-ass-1.png",h="/images/sports-fans-sports-fans/brady-ass-2.png",m="/images/sports-fans-sports-fans/brady-ass-3.png",w="/images/sports-fans-sports-fans/brady-ass-4.png",_="/images/sports-fans-sports-fans/V-J_Day_Times_Square_NYWTS-1024x833.jpg",u="/images/sports-fans-sports-fans/PhillyFans.jpg",b="/images/sports-fans-sports-fans/hug-1.png",y="/images/sports-fans-sports-fans/hug-2.png",d="/images/sports-fans-sports-fans/hug-3.png",k="/images/sports-fans-sports-fans/hug-4.png",S="/images/sports-fans-sports-fans/hug-5.png",F="/images/sports-fans-sports-fans/hug-6.png",I="/images/sports-fans-sports-fans/hug-7.png",T="/images/sports-fans-sports-fans/hug-8.png",W="/images/sports-fans-sports-fans/hug-9.png",G="/images/sports-fans-sports-fans/bro-in-law-11.png",M="/images/sports-fans-sports-fans/bro-in-law-2.png",v="/images/sports-fans-sports-fans/bro-in-law-3.png",x="/images/sports-fans-sports-fans/bro-in-law-4.png",B="/images/sports-fans-sports-fans/bro-in-law-5.png",A="/images/sports-fans-sports-fans/newspaper1.png",P="/images/sports-fans-sports-fans/escape1.png",j="/images/sports-fans-sports-fans/IGM-Sports-1-1024x610.png",q="/images/sports-fans-sports-fans/IGM-Sports-2-1024x609.png",J="/images/sports-fans-sports-fans/IGM-Sports-3-1024x682.png",D="/images/sports-fans-sports-fans/IGM-Sports-4-1024x628.png",N="/images/sports-fans-sports-fans/immortal.png",V="/images/sports-fans-sports-fans/glory1.png",C="/images/sports-fans-sports-fans/pinit_fg_en_rect_gray_20.png",O=JSON.parse('{"title":"Why Sports Fans are Sports Fans","description":"","frontmatter":{"title":"Why Sports Fans are Sports Fans","titleZh":"体育迷为何成为体育迷","date":"2014-03-18T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2014/03/sports-fans-sports-fans.html","slug":"sports-fans-sports-fans"},"headers":[],"relativePath":"posts/sports-fans-sports-fans.md","filePath":"posts/sports-fans-sports-fans.md","lastUpdated":1782886257000}'),$={name:"posts/sports-fans-sports-fans.md"};function E(L,t,R,U,Y,Z){return r(),a("div",null,[...t[0]||(t[0]=[p('<h1 id="体育迷为何成为体育迷-·-why-sports-fans-are-sports-fans" tabindex="-1">体育迷为何成为体育迷 · Why Sports Fans are Sports Fans <a class="header-anchor" href="#体育迷为何成为体育迷-·-why-sports-fans-are-sports-fans" aria-label="Permalink to &quot;体育迷为何成为体育迷 · Why Sports Fans are Sports Fans&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2014/03/sports-fans-sports-fans.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2014/03/sports-fans-sports-fans.html</a> · 2014-03-18</p></blockquote><p>世界各地,人们对体育的感受千差万别。我们先从光谱的非球迷那一端开始——</p><p><strong>对非球迷来说,在乎体育根本毫无道理。</strong></p><p>如果你是球迷,下面就是非球迷眼中你对自己球队那份爱的样子:</p><p>一群二三十岁的陌生人被付钱去互相比赛,这些比赛对现实世界毫无影响,而你却决定对这件事在乎得<strong>要命</strong>。有的队必须赢,有的队必须输,有的球员必须比别的球员打得好——而这一切都<strong>至关重要</strong>。</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/critical-fan.png" target="_blank" rel="noreferrer"><img src="'+n+'" alt="Super Fan"></a></strong></p><p>与此同时,那些必须打得好的球员有时被交易到了那些必须输的队,于是现在你又希望这些球员打得差。事实上,你真正支持的其实只是某一套球衣,不管穿着它的人是谁。</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/Jersey.png" target="_blank" rel="noreferrer"><img src="'+o+'" alt="Rooting for jerseys"></a></strong></p><p>然后还有一个事实:当你追随这支必须赢的球队时,几乎每个赛季都以他们输球告终,让你的脸变成这样:</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/Face-1.png" target="_blank" rel="noreferrer"><img src="'+e+'" alt="Letdown face"></a></strong></p><p>或者这样:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/Face-2.png" target="_blank" rel="noreferrer"><img src="'+g+'" alt="Disgusted face"></a></p><p>或者这样:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/Face-3.png" target="_blank" rel="noreferrer"><img src="'+i+'" alt="Horrified face"></a></p><p>然后,大概每 30 年一次,你如此渴望获胜的这支球队真的赢了!30 年、几千小时的时间和奉献,<strong>终于</strong>,终极目标达成了——然后呢?你的人生发生什么重大变化了吗?没有,你跑到街上去大喊大叫,然后人们开始暴动,这毫无道理,因为他们明明是开心的。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/riot1.png" target="_blank" rel="noreferrer"><img src="'+l+'" alt="Fans rioting"></a></p><p>然后你花几天读关于这场伟大胜利的文章,买件 T 恤,然后继续过你的日子。就这样。这一切就是为了这个。</p><p>我说了,这是个奇怪的现象。</p><p>然而,世界上几乎每个国家都有的少数共同点之一,就是体育迷文化。当一件事既奇怪又普遍时,背后一定有更深层的东西。 作为一个来自满城都是吓人球迷疯子的城市(波士顿)的资深球迷,我觉得有必要试着把这事儿挖到底。</p><p><strong>球迷为什么是球迷</strong></p><p><strong>体育很有娱乐性,原因如下:</strong></p><p>→ <strong>有高度的戏剧张力。</strong></p><p>正因为有那么多人在关注,也正因为发生的事会被人们长久铭记,你所观看的运动员们其实是在承担着极高的赌注,而这种赌注制造了戏剧张力。</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/golf.png" target="_blank" rel="noreferrer"><img src="'+f+'" alt="Tense putt"></a></strong></p><p>这和《美国偶像》大红大紫是同一个道理——正是<em>因为它是一档超级火爆的节目</em>,才产生了让它变得有娱乐性的戏剧张力。</p><p>当然,也有很多人是真的觉得看比赛本身就够有意思——他们爱看室内美式橄榄球联赛,爱看小联盟棒球赛,爱看高水平的野球篮球赛,因为他们就是喜欢看运动,不需要什么赌注或戏剧张力。但我觉得大多数体育迷需要那种「事关重大」的成分才能全情投入。</p><p>→ <strong>看牛人表演很爽。</strong></p><p>人类对怪物级别的天才有种迷之痴迷,无论那项技能是什么。体育正是一个绝佳的舞台,可以看到某个领域最顶尖的 0.001% 的人,和其他 0.001% 的人比拼他们最擅长的事。与此同时,你——在这件事上大概处于最好的 73% 水平——可以窝在你那张肥沙发上评头论足。挺好玩的。说到这——</p><p>→ <strong>它触及了我们内心那个渗人的角落——那个想坐在古罗马斗兽场里看人厮杀至死的角落。</strong></p><p>你怎么否认都行,但你内心是有那么一部分想这么干的。你坐在沙发上,看着人们在刺骨的寒冷或灼热的高温中飞奔、被砸中脸、还可能在两千万观众面前出洋相、亲手毁掉自己的梦想——多少是有点幸灾乐祸的。「<em>给我打</em>——拿出最好的表现来,」你一边想,一边把薯片塞进嘴里。</p><p>→ <strong>它赏心悦目。</strong></p><p>这是很多奥运项目的巨大吸引力所在,也是看勒布朗·詹姆斯 (LeBron James) 这种身姿流畅、天赋异禀的人打球特别爽的部分原因。</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/brady-ass-1.png" target="_blank" rel="noreferrer"><img src="'+c+'" alt="Brady 1"></a></strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/brady-ass-2.png" target="_blank" rel="noreferrer"><img src="'+h+'" alt="brady ass 2"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/brady-ass-3.png" target="_blank" rel="noreferrer"><img src="'+m+'" alt="Brady 3"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/brady-ass-4.png" target="_blank" rel="noreferrer"><img src="'+w+'" alt="Brady 4"></a></p><p><strong>体育让你和别人产生连结。</strong></p><p>→ <strong>在微观层面,它让家人和朋友聚在一起。</strong></p><p>很多人会为了看比赛跟朋友们凑到一块儿,而他们平时可能根本不会见面。我认识不下八个哥们儿,他们和自己老爸的主要聊天话题就是体育。体育并不是取代了那些父子之间更有意义的话题,它只是增添了一层亲密感——没有它,这层亲密感就不会存在。</p><p>→ <strong>在宏观层面上,它给更大的社群提供了另一个凝聚彼此的契机。</strong></p><p>人生中没有太多这样的时刻——你可以和素不相识的陌生人一起庆祝某件事,并对整个社群产生情感上的连结。人们热爱这种感觉——这就是为什么圣诞歌曲会让所有人都开心。整个 12 月它们在公共场合播放时,感觉我们大家一起进入了节日模式。</p><p>最能体现社群凝聚狂欢的例子就是战争结束时的庆祝:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/V-J_Day_Times_Square_NYWTS.jpg" target="_blank" rel="noreferrer"><img src="'+_+'" alt="War Celebration"></a></p><p>但由于长达六年的集体奋斗最终迎来甜美胜利这种事并不常发生,体育为我们提供了另一种方式来实现这种感觉。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/PhillyFans.jpg" target="_blank" rel="noreferrer"><img src="'+u+'" alt="Sports Celebration"></a></p><p>关键在于体育创造出一种「我们 vs 他们」的结构,让人们成为一个集体「我们」的一部分,这个「我们」可以一起胜利或一起失败。在部落时代,「我们 vs 他们」的概念是以非常具体、明显的方式存在的——而今天,尤其是在超大型国家里,这种感觉几乎没有了。体育是一种人造的方式,把更多集体的「我们」带回到我们的生活里……</p><p>→ <strong>……这也是为什么我人生经历的清单里包含了「和一个高大、吓人、凶巴巴、之前之后从没跟他说过一句话的男人搂在一起」这一项的唯一原因。</strong></p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/hug-1.png" target="_blank" rel="noreferrer"><img src="'+b+'" alt="hug 1"></a></strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/hug-2.png" target="_blank" rel="noreferrer"><img src="'+y+'" alt="hug 2"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/hug-3.png" target="_blank" rel="noreferrer"><img src="'+d+'" alt="hug 3"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/hug-4.png" target="_blank" rel="noreferrer"><img src="'+k+'" alt="hug 4"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/hug-5.png" target="_blank" rel="noreferrer"><img src="'+S+'" alt="hug 5"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/hug-6.png" target="_blank" rel="noreferrer"><img src="'+F+'" alt="hug 6"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/hug-7.png" target="_blank" rel="noreferrer"><img src="'+I+'" alt="hug 7"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/hug-8.png" target="_blank" rel="noreferrer"><img src="'+T+'" alt="hug 8"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/hug-9.png" target="_blank" rel="noreferrer"><img src="'+W+'" alt="hug 9"></a></p><p>你试着想出另一种情境——那个男人和我会在纯粹无邪的喜悦中温柔而幸福地紧紧抱在一起——祝你好运。</p><p>→ <strong>体育能让两个原本聚在一起会尴尬到爆的人,有点东西可以聊。</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/bro-in-law-11.png" target="_blank" rel="noreferrer"><img src="'+G+'" alt="Awkward conversation 1"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/bro-in-law-2.png" target="_blank" rel="noreferrer"><img src="'+M+'" alt="Awkward conversation 2"></a></p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/bro-in-law-3.png" target="_blank" rel="noreferrer"><img src="'+v+'" alt="Awkward conversation 3"></a></strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/bro-in-law-4.png" target="_blank" rel="noreferrer"><img src="'+x+'" alt="Awkward conversation 4"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/bro-in-law-5.png" target="_blank" rel="noreferrer"><img src="'+B+'" alt="Awkward conversation 5"></a></p><p><strong>体育圈里有大量的八卦。</strong></p><p>体育迷对著名运动员场外那些狗血剧情有一种病态的痴迷,就跟人们迷恋电影明星的生活一样。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/newspaper1.png" target="_blank" rel="noreferrer"><img src="'+A+'" alt="Sports gossip"></a><br><strong>体育提供了一种逃离生活的方式。</strong></p><p>→ <strong>生活是件非常以自我为中心的事情,当你被自己的破事搞烦了的时候,体育往往是个不错的转移注意力的地方。尤其是在你的人生烂透了的日子里。</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/escape1.png" target="_blank" rel="noreferrer"><img src="'+P+'" alt="Escape to sports"></a></p><p>→ <strong>对于你那种<a href="https://waitbutwhy.com/2013/10/why-procrastinators-procrastinate.html" target="_blank" rel="noreferrer">病入膏肓的拖延症</a>,它是个完美的工具。</strong></p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/IGM-Sports-1.png" target="_blank" rel="noreferrer"><img src="'+j+'" alt="IGM Sports 1"></a></strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/IGM-Sports-2.png" target="_blank" rel="noreferrer"><img src="'+q+'" alt="IGM Sports 2"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/IGM-Sports-3.png" target="_blank" rel="noreferrer"><img src="'+J+'" alt="IGM Sports 3"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/IGM-Sports-4.png" target="_blank" rel="noreferrer"><img src="'+D+'" alt="IGM Sports 4"></a></p><p>→ <strong>有时候我觉得,我们甚至可能是在把体育当作一种途径,让自己依附于某个不朽的东西。</strong></p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/immortal.png" target="_blank" rel="noreferrer"><img src="'+N+'" alt="Sports fan immortality"></a></strong></p><p>而说到底……</p><p><strong>在这样一个大多数人的生活里都没什么英雄凯旋时刻的时代,体育让我们能捕捉到一丝丝荣耀的滋味。</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/glory1.png" target="_blank" rel="noreferrer"><img src="'+V+'" alt="Glory"></a></p><p><strong>相关 Wait But Why 文章</strong></p><p><a href="https://waitbutwhy.com/2013/10/10-types-of-30-year-old-single-guys.html" target="_blank" rel="noreferrer">10 种 30 岁单身男的类型</a><a href="https://waitbutwhy.com/2014/05/secretly-hate-bars.html" target="_blank" rel="noreferrer">为什么你其实偷偷讨厌那些酷炫酒吧</a><a href="https://waitbutwhy.com/2013/10/the-battle-to-lose-independent-vote.html" target="_blank" rel="noreferrer">争夺独立选民的落败之战</a></p><hr><p>如果你喜欢 Wait But Why,请订阅我们的**<a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a>**,新文章发布时我们会发给你。</p><p>想支持 Wait But Why,请访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。</p><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2014/03/sports-fans-sports-fans.html&amp;description=Why%20Sports%20Fans%20are%20Sports%20Fans" target="_blank" rel="noreferrer"><img src="'+C+'" alt=""></a></p>',86)])])}const z=s($,[["render",E]]);export{O as __pageData,z as default};
